patch:
--- a/shift_register.sv
+++ b/shift_register.sv
@@ -8,11 +8,11 @@ module shift_register_32bit(
 module controller;
   logic [31:0] data_in, data_out;
   logic clk, enable;

   shift_register_32bit shifter (
-    .output_data(data_in),
+    .input_data(data_in),
     .clk(clk),
     .enable(enable),
-    .input_data(data_out)
+    .output_data(data_out)
   );
 endmodule

before_code:
module shift_register_32bit(
  input [31:0] input_data,
  input clk,
  input enable,
  output [31:0] output_data
);
  always @(posedge clk) begin
    if (enable)
      output_data <= input_data;
  end
endmodule

module controller;
  logic [31:0] data_in, data_out;
  logic clk, enable;

  shift_register_32bit shifter (
    .output_data(data_in),
    .clk(clk),
    .enable(enable),
    .input_data(data_out)
  );
endmodule

after_code:
module shift_register_32bit(
  input [31:0] input_data,
  input clk,
  input enable,
  output [31:0] output_data
);
  always @(posedge clk) begin
    if (enable)
      output_data <= input_data;
  end
endmodule

module controller;
  logic [31:0] data_in, data_out;
  logic clk, enable;

  shift_register_32bit shifter (
    .input_data(data_in),
    .clk(clk),
    .enable(enable),
    .output_data(data_out)
  );
endmodule
